// Real grid is auto-generated from GitHub contributions for enzomanuelmangano (2018-2026)
export const CONTRIBUTION_GRID_COLS = 53;
export const CONTRIBUTION_GRID_ROWS = 63;
export const CONTRIBUTION_YEARS = [
  2018, 2019, 2020, 2021, 2022, 2023, 2024, 2025, 2026,
];

/**
 * Default source for `CONTRIBUTION_GRID` when not using the in-app toggle.
 * Prefer `getContributionGrid(useReal)` / the GitHubTerrain "My contributions" switch.
 */
export const USE_REAL_CONTRIBUTION_GRID = false;

/** Smooth float field (box blur) so quantized levels read as foothills / ranges. */
function smoothFloat2D(grid: number[][], passes: number): number[][] {
  const cols = grid.length;
  const rows = grid[0].length;
  let cur = grid.map(column => [...column]);
  for (let p = 0; p < passes; p++) {
    const next: number[][] = [];
    for (let c = 0; c < cols; c++) {
      next[c] = [];
      for (let r = 0; r < rows; r++) {
        let sum = 0;
        let count = 0;
        for (let dc = -1; dc <= 1; dc++) {
          for (let dr = -1; dr <= 1; dr++) {
            const cc = c + dc;
            const rr = r + dr;
            if (cc >= 0 && cc < cols && rr >= 0 && rr < rows) {
              sum += cur[cc][rr];
              count += 1;
            }
          }
        }
        next[c][r] = sum / count;
      }
    }
    cur = next;
  }
  return cur;
}

function fbm2(nx: number, ny: number): number {
  let v = 0;
  let a = 0.48;
  let f = 1;
  for (let i = 0; i < 5; i++) {
    v += a * Math.sin((nx * 2.4 + ny * 1.6 + i * 0.4) * f * Math.PI * 2);
    v += a * 0.55 * Math.cos((nx * 1.2 - ny * 2.1 + 0.8) * f * Math.PI * 2);
    a *= 0.5;
    f *= 2.05;
  }
  return v;
}

function smoothstep(edge0: number, edge1: number, x: number): number {
  const t = Math.max(0, Math.min(1, (x - edge0) / (edge1 - edge0)));
  return t * t * (3 - 2 * t);
}

/**
 * Reference-style contribution “mountains”: one dominant diagonal ridge
 * (mid-left → far right), a taller back-corner massif, broad lower foreground
 * plateau, soft island edge — then blur + 0–4 buckets like the GitHub ramp.
 */
function buildAdHocContributionGrid(): number[][] {
  const cols = CONTRIBUTION_GRID_COLS;
  const rows = CONTRIBUTION_GRID_ROWS;

  const raw: number[][] = [];
  for (let c = 0; c < cols; c++) {
    const col: number[] = [];
    for (let r = 0; r < rows; r++) {
      const nx = c / Math.max(cols - 1, 1);
      const ny = r / Math.max(rows - 1, 1);

      // Main diagonal spine (screenshot: strong ridge across the chart)
      const ridgeLine = ny - (0.17 + 0.52 * nx);
      const ridge = Math.exp(-(ridgeLine * ridgeLine) / 0.028) * 1.05;

      // Along-ridge undulation (tiered “steps” without noise)
      const along = nx * 0.72 + ny * 0.68;
      const undulate =
        0.1 * Math.sin(along * Math.PI * 4.2 + 0.35) +
        0.05 * Math.sin(along * Math.PI * 8.1 + 1.1);

      // Back / upper-right summit cluster
      const backMassif =
        Math.exp(-(((nx - 0.84) ** 2 + (ny - 0.14) ** 2) / 0.026)) * 0.95 +
        Math.exp(-(((nx - 0.72) ** 2 + (ny - 0.22) ** 2) / 0.04)) * 0.45;

      // Foreground: wide lower plateau (high ny ≈ bottom of heatmap)
      const foreBase = 0.14 * (0.55 + 0.45 * smoothstep(0.38, 0.96, ny));
      const foreDamp = 0.62 + 0.38 * (1 - smoothstep(0.48, 0.98, ny));

      // Soft diamond / island (matches elliptical mask in renderer)
      const dx = (nx - 0.5) / 0.48;
      const dz = (ny - 0.5) / 0.46;
      const edge = 1 - smoothstep(0.62, 1.08, dx * dx + dz * dz);

      const micro = fbm2(nx, ny) * 0.055;
      let h =
        (ridge + undulate + backMassif + foreBase) *
          foreDamp *
          (0.78 + 0.22 * edge) +
        micro;

      col.push(Math.max(0, h));
    }
    raw.push(col);
  }

  const smoothed = smoothFloat2D(raw, 5);
  let min = Infinity;
  let max = -Infinity;
  for (const col of smoothed) {
    for (const v of col) {
      if (v < min) min = v;
      if (v > max) max = v;
    }
  }
  const span = max - min || 1;

  const grid: number[][] = [];
  for (let c = 0; c < cols; c++) {
    const col: number[] = [];
    for (let r = 0; r < rows; r++) {
      const t = (smoothed[c][r] - min) / span;
      let level: number;
      if (t < 0.2) level = 0;
      else if (t < 0.36) level = 1;
      else if (t < 0.54) level = 2;
      else if (t < 0.72) level = 3;
      else level = 4;
      col.push(level);
    }
    grid.push(col);
  }
  return grid;
}

